ores principales","trafficLast24":"Tráfico (24h)","totalClean":"Total limpio","totalBlocked":"Total bloqueado","uptime":"Disponibilidad","attackOrigins":"Orígenes de ataques"},"useCases":{"title":"Protección para cada caso","subtitle":"Desde servidores de juego hasta infraestructura empresarial.","pain":"Problema","solution":"Solución","outcome":"Resultado","items":{"games":{"title":"Servidores de juegos","pain":"Lag y desconexiones durante ataques","solution":"Mitigación sub-10ms mantiene el juego fluido","outcome":"Cero tiempo de inactividad"},"web":{"title":"Aplicaciones web","pain":"Sitios no disponibles durante inundaciones HTTP","solution":"Protección L7 filtra solicitudes maliciosas","outcome":"Disponibilidad constante"},"api":{"title":"APIs","pain":"Limitado por atacantes","solution":"Limitación inteligente de tasa","outcome":"APIs receptivas para usuarios reales"},"voip":{"title":"Servicios VoIP","pain":"Calidad degradada bajo inundaciones SIP","solution":"Mitigación consciente del protocolo","outcome":"Llamadas claras sin interrupciones"},"vpn":{"title":"VPN corporativa","pain":"Trabajadores remotos no pueden conectarse","solution":"Protección siempre activa para VPN","outcome":"Acceso remoto seguro"},"ecommerce":{"title":"E-commerce","pain":"Pérdida de ingresos por ataques checkout","solution":"Mitigación bot protege transacciones","outcome":"Compras seguras"}}},"faq":{"title":"Preguntas frecuentes","subtitle":"Todo sobre nuestros servicios de protección DDoS.","items":[{"q":"¿Diferencia entre protección L3/L4 y L7?","a":"L3/L4 maneja ataques volumétricos, L7 ataques de aplicación. Recomendamos ambos."},{"q":"¿Soportan protección específica para juegos?","a":"¡Sí! Optimizado para Minecraft, FiveM, Rust, ARK y más."},{"q":"¿La mitigación añade latencia?","a":"Menos de 1ms en condiciones normales."},{"q":"¿Cómo integro mi infraestructura?","a":"1) Regístrate. 2) Actualiza DNS o BGP. 3) Protección activa en minutos."},{"q":"¿Necesito cambiar registros DNS?",